import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic_evenSpread() {
        // [100,200,300,400,500] n=5, maxAmount=500
        // bucket(100)=min(100*5/501,4)=min(0,4)=0
        // bucket(200)=min(1000/501,4)=min(1,4)=1 ... each lands in its own bucket
        int[] result = new Solution().spendingHistogram(new int[]{100, 200, 300, 400, 500}, 5);
        assertArrayEquals(new int[]{1, 1, 1, 1, 1}, result);
    }

    @Test
    void allZeroAmounts() {
        // maxAmount=0: formula gives bucket=min(0*n/1, n-1)=0 for all
        int[] result = new Solution().spendingHistogram(new int[]{0, 0, 0}, 3);
        assertArrayEquals(new int[]{3, 0, 0}, result);
    }

    @Test
    void allSameNonZero() {
        // [100,100,100] n=3, maxAmount=100
        // bucket=min((int)(100*3/101),2)=min(2,2)=2 -> all in bucket 2
        int[] result = new Solution().spendingHistogram(new int[]{100, 100, 100}, 3);
        assertArrayEquals(new int[]{0, 0, 3}, result);
    }

    @Test
    void empty() {
        // empty amounts -> all-zero array of length n
        int[] result = new Solution().spendingHistogram(new int[]{}, 4);
        assertArrayEquals(new int[]{0, 0, 0, 0}, result);
    }

    @Test
    void singleBucket() {
        // n=1: every amount goes into bucket 0 regardless
        int[] result = new Solution().spendingHistogram(new int[]{10, 500, 999}, 1);
        assertArrayEquals(new int[]{3}, result);
    }

    @Test
    void singleAmount() {
        // one transaction, n=5, maxAmount=250
        // bucket=min((int)(250*5/251),4)=min(int(1250/251),4)=min(4,4)=4
        int[] result = new Solution().spendingHistogram(new int[]{250}, 5);
        assertArrayEquals(new int[]{0, 0, 0, 0, 1}, result);
    }

    @Test
    void amountAtMaxFallsInLastBucket() {
        // The +1 in divisor ensures maxAmount itself lands at bucket n-1, not n
        // amounts=[0, 200], n=2, maxAmount=200
        // bucket(0)  = min(0*2/201, 1) = 0
        // bucket(200)= min((int)(200*2/201), 1) = min(1, 1) = 1
        int[] result = new Solution().spendingHistogram(new int[]{0, 200}, 2);
        assertArrayEquals(new int[]{1, 1}, result);
    }
}
